<?php

namespace Src\Containers\Patient\Actions;

use Illuminate\Support\Facades\DB;
use Illuminate\Support\Facades\Log;
use Src\Ship\Parents\Actions\Action;
use Src\Containers\Patient\Models\Patient;
use Src\Containers\Patient\Events\PatientReplicationChanged;
use Src\Containers\Patient\Support\PatientReplicationLinks;
use Src\Containers\Patient\Tasks\SetPatientRegionTask;
use Src\Containers\Patient\Tasks\SyncCaseDataForReplicaTask;
use Src\Containers\Patient\Tasks\SyncBodyPartsForReplicaTask;

class SyncReplicatedPatientsAction extends Action
{
    private const EXCLUDED_FIELDS = [
        'id',
        'owner_id',
        'owner_clinic_id',
        'clinic_id',
        'clinic_case_id',
        'created_by',
        'location_id',
        'card_settings',
        'card_layout',
        'created_at',
        'updated_at',
        'deleted_at',
    ];

    public function __construct(
        private SetPatientRegionTask $setPatientRegionTask,
        private SyncCaseDataForReplicaTask $syncCaseDataForReplicaTask,
        private SyncBodyPartsForReplicaTask $syncBodyPartsForReplicaTask
    ) {}

    public function run(Patient $ownerPatient): void
    {
        DB::transaction(function () use ($ownerPatient) {
            $ownerPatientId = $ownerPatient->id;

            $ownerPatient = Patient::withoutSoftDeleted()
                ->lockForUpdate()
                ->find($ownerPatientId);

            if (!$ownerPatient) {
                Log::warning("Owner patient #{$ownerPatientId} not found or deleted during sync");
                return;
            }

            $replicatedPatientIds = PatientReplicationLinks::replicaPatientIdsForOwner($ownerPatient);

            if ($replicatedPatientIds === null) {
                Log::warning("Attempted to sync non-owner patient", [
                    'patient_id' => $ownerPatient->id,
                    'owner_id' => $ownerPatient->owner_id,
                ]);
                return;
            }

            if (empty($replicatedPatientIds)) {
                Log::debug("No replicated patients found for owner #{$ownerPatient->id}");
                return;
            }

            $syncData = $this->prepareSyncData($ownerPatient);

            if (empty($syncData)) {
                Log::debug("No data to sync for patient #{$ownerPatient->id}");
                return;
            }

            $updated = $this->updateReplicatedPatients($replicatedPatientIds, $syncData);

            $this->syncCaseDataAndBodyParts($ownerPatient, $replicatedPatientIds);

            PatientReplicationChanged::dispatch(
                array_merge([$ownerPatient->id], $replicatedPatientIds)
            );

            $this->logSyncResult($ownerPatient, $replicatedPatientIds, $updated);
        });
    }

    private function prepareSyncData(Patient $ownerPatient): array
    {
        $allAttributes = array_keys($ownerPatient->getAttributes());
        $guarded = $ownerPatient->getGuarded();
        $fillable = array_diff($allAttributes, $guarded);
        $syncFields = array_diff($fillable, self::EXCLUDED_FIELDS);
        $syncData = $ownerPatient->only($syncFields);

        return $this->setPatientRegionTask->run($syncData);
    }

    private function updateReplicatedPatients(array $replicatedPatientIds, array $syncData): int
    {
        $syncData['updated_at'] = now();

        return Patient::withoutSoftDeleted()
            ->whereIn('id', $replicatedPatientIds)
            ->update($syncData);
    }

    private function syncCaseDataAndBodyParts(Patient $ownerPatient, array $replicatedPatientIds): void
    {
        $ownerPatient->load([
            'caseData.relatedCases',
            'caseData.subsequentCases',
            'bodyParts'
        ]);

        $replicatedPatients = Patient::withoutSoftDeleted()
            ->with(['caseData', 'bodyParts'])
            ->whereIn('id', $replicatedPatientIds)
            ->get();

        foreach ($replicatedPatients as $replicaPatient) {
            $this->syncCaseDataForReplicaTask->run($ownerPatient, $replicaPatient);
            $this->syncBodyPartsForReplicaTask->run($ownerPatient, $replicaPatient);
        }
    }

    private function logSyncResult(Patient $ownerPatient, array $replicatedPatientIds, int $updated): void
    {
        Log::info("Synced {$updated} replicated patients from owner #{$ownerPatient->id}", [
            'owner_patient_id' => $ownerPatient->id,
            'replicated_count' => count($replicatedPatientIds),
            'updated_count' => $updated,
        ]);
    }
}


