<?php

namespace Src\Containers\Patient\Support;

use Illuminate\Database\Eloquent\Collection as EloquentCollection;
use Illuminate\Support\Collection;
use Src\Containers\Patient\Models\ClinicPatientReplicateItem;
use Src\Containers\Patient\Models\Patient;

final class BulkPatientReplicationLinks
{
    public const RELATION = 'extendReplicatedPatients';

    public static function attach(Collection $patients, string $relation = self::RELATION): Collection
    {
        $patientIdsByPatient = self::replicatedPatientIdsByPatient($patients);
        $allReplicatedPatientIds = self::normalizePatientIds(
            array_merge(...array_values($patientIdsByPatient ?: [[]]))
        );

        $replicatedPatientsById = empty($allReplicatedPatientIds)
            ? collect()
            : Patient::withoutSoftDeleted()
                ->whereIn('patients.id', $allReplicatedPatientIds)
                ->with('userProvider')
                ->get()
                ->keyBy('id');

        return $patients->each(function (Patient $patient) use ($patientIdsByPatient, $replicatedPatientsById, $relation) {
            $replicatedPatients = [];

            foreach ($patientIdsByPatient[(int) $patient->id] ?? [] as $patientId) {
                $replicatedPatient = $replicatedPatientsById->get($patientId);

                if ($replicatedPatient !== null) {
                    $replicatedPatients[] = $replicatedPatient;
                }
            }

            $patient->setRelation($relation, new EloquentCollection($replicatedPatients));
        });
    }

    public static function replicatedPatientIdsByPatient(Collection $patients): array
    {
        $patientsById = $patients->keyBy(fn(Patient $patient) => (int) $patient->id);
        $patientIds = self::normalizePatientIds($patientsById->keys()->all());

        if (empty($patientIds)) {
            return [];
        }

        $graphFamilies = self::expandGraphFamiliesWithLegacyLinks(
            self::graphFamiliesForPatients($patientsById)
        );
        $legacyFamilies = self::legacyFamiliesForPatients($patientsById, array_keys($graphFamilies));

        $families = [];

        foreach ($patientIds as $patientId) {
            if (isset($graphFamilies[$patientId])) {
                $families[$patientId] = self::normalizePatientIds(
                    array_diff($graphFamilies[$patientId], [$patientId])
                );

                continue;
            }

            $families[$patientId] = $legacyFamilies[$patientId] ?? [];
        }

        return $families;
    }

    private static function graphFamiliesForPatients(Collection $patientsById): array
    {
        $families = self::graphSeedPatientIdsByRoot($patientsById);
        $patientRoots = [];
        $visitedGroupRoots = [];
        $rootsWithGraphLinks = [];

        foreach ($families as $rootId => $seedPatientIds) {
            foreach ($seedPatientIds as $patientId) {
                self::addRootForPatient($patientRoots, $patientId, $rootId);
            }
        }

        $pendingPatientIds = self::normalizePatientIds(
            array_merge(...array_values($families ?: [[]]))
        );

        while (!empty($pendingPatientIds)) {
            $groupRows = ClinicPatientReplicateItem::query()
                ->whereIn('patient_id', $pendingPatientIds)
                ->get(['patient_id', 'clinic_patient_replicate_id']);

            $newGroupRoots = [];

            foreach ($groupRows as $groupRow) {
                $patientId = (int) $groupRow->patient_id;
                $groupId = (int) $groupRow->clinic_patient_replicate_id;

                foreach ($patientRoots[$patientId] ?? [] as $rootId) {
                    if (isset($visitedGroupRoots[$rootId][$groupId])) {
                        continue;
                    }

                    $visitedGroupRoots[$rootId][$groupId] = $groupId;
                    $newGroupRoots[$groupId][$rootId] = $rootId;
                    $rootsWithGraphLinks[$rootId] = true;
                }
            }

            if (empty($newGroupRoots)) {
                break;
            }

