use Src\Containers\Patient\Support\PatientReplicationLinks;

class FindReplicatedPatientInClinicTask extends Task
{
    public function run(Patient $ownerPatient, Clinic $clinic): ?Patient
    {
        $patientIds = PatientReplicationLinks::replicaPatientIdsForOwner($ownerPatient);

        if ($patientIds === null || empty($patientIds)) {
