<?php

namespace Src\Containers\Patient\Tasks;

use Src\Containers\Clinic\Models\Clinic;
use Src\Containers\Patient\DTO\PatientReplicateDTO;
use Src\Ship\Parents\Tasks\Task;
use Src\Containers\Patient\Models\Patient;

class ValidateClinicForReplicationTask extends Task
{
    public function run(Patient $ownerPatient, PatientReplicateDTO $dto): void
    {
        if (in_array($ownerPatient->clinic_id, $dto->clinic_ids)) {
            throw new \InvalidArgumentException(
                "Cannot replicate patient #{$ownerPatient->id} to the same clinic #{$ownerPatient->clinic_id}",
                422
            );
        }

        $allowedClinicIds = $this->replicationFamilyClinicIds($ownerPatient);
        $requestedClinicIds = array_values(array_unique(array_map('intval', $dto->clinic_ids)));
        $invalidClinicIds = array_values(array_diff($requestedClinicIds, $allowedClinicIds));

        if (!empty($invalidClinicIds)) {
            throw new \InvalidArgumentException(
                "Cannot replicate patient #{$ownerPatient->id} outside the clinic family: " . implode(', ', $invalidClinicIds),
                422
            );
        }
    }

    private function replicationFamilyClinicIds(Patient $patient): array
    {
        $clinic = Clinic::withoutGlobalScopes()
            ->whereNull('deleted_at')
            ->find($patient->clinic_id);

        if ($clinic === null) {
            return [(int) $patient->clinic_id];
        }

        $ownerClinicId = (int) ($clinic->owner_id ?? $clinic->id);

        return Clinic::withoutGlobalScopes()
            ->whereNull('deleted_at')
            ->where(function ($query) use ($ownerClinicId) {
                $query->where('id', $ownerClinicId)
                    ->orWhere('owner_id', $ownerClinicId);
            })
            ->pluck('id')
            ->map(fn ($clinicId) => (int) $clinicId)
            ->values()
            ->all();
    }
}

